from jinja2 import Environment

captured = []

class T:
    def gettext(self, s):
        return 'G:' + s
    def ngettext(self, s, p, n):
        return 'NG:' + (s if n==1 else p)
    def dgettext(self, d, s):
        captured.append(('dgettext', d, s))
        return f'D[{d}]:' + s
    def dngettext(self, d, s, p, n):
        captured.append(('dngettext', d, s, p, n))
        return f'DN[{d}]:' + (s if n==1 else p)

env = Environment(extensions=['jinja2.ext.i18n'])
env.install_gettext_translations(T(), newstyle=True)

t = env.from_string('{% trans domain=\"mydomain\" %}Hello {{ x }}{% endtrans %}')
print(t.render(x='World'))

t2 = env.from_string('{% trans domain=\"mydomain\", count=n %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t2.render(n=2))
print(captured)

t3 = env.from_string('{% trans %}plain{% endtrans %}')
print(t3.render())
"
